import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it.todo("should return base premium plus processing fee for a single sword (new customer, first policy)");
    it.todo("should apply 50% cursed surcharge to the base premium");
    it.todo("should apply 30% high enchantment surcharge for enchantment level >= 5");
    it.todo("should apply 20% loyalty discount for customer with >= 2 years");
    it.todo("should apply 10% initial assessment surcharge for first insurance and 15% discount for subsequent contracts");
    it.todo("should use building block rate (60 G) for a set of 3 alike components");
  });

  describe("claim", () => {
    it.todo("should return zero payout when damage is at or below the 100 G deductible");
    it.todo("should return damage minus deductible as payout for standard damage above the deductible");
    it.todo("should fully reimburse damage to items made of dragon material");
    it.todo("should reimburse 50% of damage to items with enchantment level >= 8");
    it.todo("should decrease remainingCap by the payout amount after each claim");
  });
});

