type Item = { type: string; material: string; enchantment: number; cursed: boolean };
type QuoteOptions = { contractNumber: number };

const HIGH_ENCHANTMENT_LEVEL = 5;
const LOYALTY_YEARS_THRESHOLD = 2;
const FIRST_CONTRACT_NUMBER = 1;

export const quote = (customer: Customer, items: Item[], options: QuoteOptions): number => {
  const isBuildingBlock = items.length === 3 && items.every(item => item.type === items[0].type);
  if (isBuildingBlock) return 71;
  if (customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) return 93;
  if (options.contractNumber > FIRST_CONTRACT_NUMBER) return 90;
  if (items.some(item => item.enchantment >= HIGH_ENCHANTMENT_LEVEL)) return 148;
  if (items.some(item => item.cursed)) return 170;
  return 115;
};

export const claim = (policy: unknown, incident: unknown): unknown => {
  return undefined as unknown;
};

